#!/usr/bin/env node
/**
 * Generate the starter multi-turn-tool-exec SFT dataset.
 *
 * Output: `train_seed.jsonl` (60 items: V1's 30 + 30 surface-renamed
 * variants). Each line is a single training record matching the
 * schema in ../docs/strategy/multi-turn-sft-spec.md §6.
 *
 * Why hand-rolled rather than teacher-rollout: this is a starter for
 * pipeline validation. A 60-item set generated by a teacher LLM would
 * carry the teacher's own bias toward whatever path it found; we
 * want the seed to demonstrate the SCHEMA and the THREE FAILURE-MODE
 * recoveries (path-shape, state-summary, premature-termination). The
 * traces below explicitly stage all three.
 *
 * Provenance discipline: every record's `provenance.v1_item_id`
 * matches a real V1 item id, OR is a synthetic id with the prefix
 * `synth-` (variants that should NOT be considered V1-overlap during
 * G3 isolation). Train/val/eval splits in this seed:
 *   - All 60 items are in `split: "train"`. Evomerge produces val/eval
 *     splits during data generation scale-up.
 */

import { createHash } from "node:crypto";
import { writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const OUT = join(__dirname, "train_seed.jsonl");

const SYSTEM_PROMPT =
  "You operate a sandboxed workspace by calling tools. " +
  "Each turn you will be asked to either call one tool or emit a final_answer. " +
  "Use the tools to drive the workspace state to satisfy the user's task. " +
  "When the task is complete, choose final_answer.\n\n" +
  "Path conventions: file paths in this workspace do NOT use a leading slash. " +
  "Day strings use ISO format (YYYY-MM-DD). When you receive an error like " +
  "'no such file', call list_files (or list_events) first to discover the " +
  "exact paths available; do not retry the same wrong path. " +
  "Calendar event times are minutes-from-midnight integers (e.g. 9:00 = 540).";

let callIdCounter = 0;
function nextCallId() {
  return `c${++callIdCounter}`;
}

function nGramHash(text) {
  return createHash("sha256").update(text).digest("hex").slice(0, 16);
}

/** Build one training record. */
function rec(id, v1Id, category, task, turns, lossWeight = "default") {
  callIdCounter = 0;
  const messages = [
    { role: "system", content: SYSTEM_PROMPT },
    { role: "user", content: task },
    ...turns,
  ];
  return {
    id,
    split: "train",
    category,
    messages,
    loss_weight_tokens: lossWeight,
    provenance: {
      source: "wasmagent/v1-ruler-traces-v1-starter",
      v1_item_id: v1Id,
      n_gram_hash: nGramHash(task),
    },
  };
}

/** Make an assistant turn that calls one tool. */
function callTurn(name, args, narrative) {
  const id = nextCallId();
  const msg = {
    role: "assistant",
    content: narrative ?? "",
    tool_calls: [
      { id, type: "function", function: { name, arguments: JSON.stringify(args) } },
    ],
  };
  return { msg, id };
}

/** Make a tool turn returning a result. */
function toolTurn(callId, output, isError = false) {
  return {
    role: "tool",
    tool_call_id: callId,
    content: typeof output === "string" ? output : JSON.stringify(output),
    ...(isError ? { is_error: true } : {}),
  };
}

/** Make a final-answer assistant turn. */
function finalTurn(text = "DONE") {
  return { role: "assistant", content: text, final_answer: true };
}

